if __name__ == "__main__":
    # 1. Read existing awrad.json
    try:
        with open('app/src/main/assets/data/awrad.json', 'r', encoding='utf-8') as f:
            awrad_data = json.load(f)
    except FileNotFoundError:
        awrad_data = []

    # 2. Update English content and title_en
    for item in awrad_data:
        item_id = item['id']
        if item_id in DALAIL_ENGLISH:
            item['translation'] = DALAIL_ENGLISH[item_id]['translation']
            item['title_en'] = DALAIL_ENGLISH[item_id]['title_en']
            print(f"Updated English for {item_id}")

    # 3. Save updated file (preserves sorting from previous step)
    with open('app/src/main/assets/data/awrad.json', 'w', encoding='utf-8') as f:
        json.dump(awrad_data, f, ensure_ascii=False, indent=2)

    print("\nSuccessfully updated Dalail English content!")

